import '../../../status-pill/status-dot/status-dot.component.js';
import type { StatusDot } from '../../../status-pill/status-dot/status-dot.component.js';

const template = document.createElement('template');
template.innerHTML = `
  <div class="section">
    <div class="section-header">
      <status-dot id="dot" title="Connectivity"></status-dot>
      <h3 id="section-title"></h3>
    </div>
    <p id="message"></p>
  </div>
`;

export class ConnectivitySection extends HTMLElement {
    private dot!: StatusDot;
    private sectionTitle!: HTMLHeadingElement;
    private message!: HTMLParagraphElement;

    private readonly onStatusChange = () => this.render();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.appendChild(template.content.cloneNode(true));
        this.dot = shadow.getElementById('dot') as StatusDot;
        this.sectionTitle = shadow.getElementById('section-title') as HTMLHeadingElement;
        this.message = shadow.getElementById('message') as HTMLParagraphElement;
    }

    connectedCallback() {
        window.addEventListener('online', this.onStatusChange);
        window.addEventListener('offline', this.onStatusChange);
        this.render();
    }

    disconnectedCallback() {
        window.removeEventListener('online', this.onStatusChange);
        window.removeEventListener('offline', this.onStatusChange);
    }

    static getStatus(online: boolean) {
        return {
            color: (online ? 'green' : 'red') as 'green' | 'red',
            label: online ? null : 'Offline'
        };
    }

    private render() {
        const online = navigator.onLine;
        const status = ConnectivitySection.getStatus(online);
        this.dot.setAttribute('color', status.color);
        this.sectionTitle.textContent = `Connectivity: ${online ? 'Online' : 'Offline'}`;
        this.message.textContent = online
            ? 'App is connected to the internet. Live features available.'
            : 'App is running in offline mode. Local changes will be synced later.';
    }
}

customElements.define('connectivity-status-section', ConnectivitySection);