import { PI_GATEWAY_URL } from '../config.js';

// ── Types ───────────────────────────────────────────────────────────────────

export type GatewayState = 'PRESENT' | 'MISSING' | 'LISTENING' | 'CLOSED' | 'RUNNING' | 'DOWN' | 'UNKNOWN';

export interface ServerStatus {
    mac: GatewayState;
    dropbear: GatewayState;
    ssh: GatewayState;
    immich: GatewayState;
}

/**
 * Boot stage derived from combined status:
 * off → present → dropbear → ssh → running
 * unreachable = the Pi gateway itself cannot be reached (not on home network)
 */
export type BootStage = 'off' | 'present' | 'dropbear' | 'ssh' | 'running' | 'unreachable';

export interface ActionResult {
    success: boolean;
    message?: string;
    error?: string;
}

// ── Stage derivation ────────────────────────────────────────────────────────

export function deriveBootStage(status: ServerStatus): BootStage {
    if (status.ssh === 'LISTENING' && status.immich === 'RUNNING') return 'running';
    if (status.ssh === 'LISTENING') return 'ssh';
    if (status.dropbear === 'LISTENING') return 'dropbear';
    if (status.mac === 'PRESENT') return 'present';
    return 'off';
}

export function stageLabel(stage: BootStage): string {
    switch (stage) {
        case 'off':         return 'Off';
        case 'present':     return 'Waking…';
        case 'dropbear':    return 'Unlocking…';
        case 'ssh':         return 'Booting…';
        case 'running':     return 'Running';
        case 'unreachable': return 'Not home';
    }
}

export function stageColor(stage: BootStage): 'red' | 'orange' | 'green' | 'gray' {
    switch (stage) {
        case 'running':     return 'green';
        case 'ssh':
        case 'dropbear':
        case 'present':     return 'orange';
        case 'off':         return 'red';
        case 'unreachable': return 'gray';
    }
}

// ── Status polling ──────────────────────────────────────────────────────────

async function fetchState(endpoint: string): Promise<GatewayState> {
    const res = await fetch(`${PI_GATEWAY_URL}${endpoint}`);
    const data: { state: string } = await res.json();
    return (data.state ?? 'UNKNOWN') as GatewayState;
}

export async function fetchServerStatus(): Promise<ServerStatus> {
    const [mac, dropbear, ssh, immich] = await Promise.all([
        fetchState('/api/status/mac'),
        fetchState('/api/status/dropbear'),
        fetchState('/api/status/ssh'),
        fetchState('/api/status/immich'),
    ]);
    return { mac, dropbear, ssh, immich };
}

export async function isPiGatewayReachable(): Promise<boolean> {
    try {
        await fetchState('/api/status/mac');
        return true;
    } catch {
        return false;
    }
}

// ── Actions ─────────────────────────────────────────────────────────────────

async function postAction(endpoint: string, password?: string): Promise<ActionResult> {
    const res = await fetch(`${PI_GATEWAY_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        ...(password !== undefined ? { body: JSON.stringify({ password }) } : {}),
    });
    return res.json() as Promise<ActionResult>;
}

export const wake     = ()               => postAction('/api/action/wake');
export const unlock   = (pw: string)     => postAction('/api/action/unlock', pw);
export const boot     = (pw: string)     => postAction('/api/action/boot', pw);
export const shutdown = (pw: string)     => postAction('/api/action/shutdown', pw);
export const hardReboot = (pw: string)   => postAction('/api/action/hard-reboot', pw);
