import type { ActivitySource, ActivityType, NewActivity } from '@motivation/shared';
import { getAppTimeZone, appTodayPlainDate } from './app-timezone.service.js';
import { HealthService } from './health.service.js';
import { createComponentLogger } from '../utils/component-logger.js';

// Ships to the server client-log stream — `npm run logs -w server -- --module=hc-sync`.
const log = createComponentLogger('hc-sync');

/**
 * Health Connect bridge sync (story 250, replacing the dead Strava API).
 *
 * The sideloaded bridge app (hc-bridge/) serves Health Connect data on
 * loopback; the PWA fetches it directly — localhost is potentially-trustworthy
 * so there is no mixed-content block and the service worker passes the request
 * through untouched (spike 249). Mapped activities are pushed through the
 * normal health API (POST /activities + PATCH /cardio-details), so dedup rides
 * the existing unique `external_id` index and offline behavior matches manual
 * entry.
 */

// Story 257: resolved in config.ts (MOTIVATION_HC_BRIDGE_HOST/PORT) so
// instance builds can point the bridge at the mock stub; re-exported here
// because this module owns the bridge API surface.
import { HC_BRIDGE_URL } from '../config.js';
export { HC_BRIDGE_URL };

/**
 * The bridge returns 429 `{reason:"rate_limited"}` when Health Connect throttles
 * reads (its per-app read quota). Distinct from a generic failure so the Status
 * screen can show a cooldown + retry instead of an opaque error.
 */
export class HcRateLimitError extends Error {
    readonly reason = 'rate_limited';
    constructor(message = 'Health Connect is rate-limiting reads') {
        super(message);
        this.name = 'HcRateLimitError';
    }
}

/**
 * Chrome intent URL that launches (or foregrounds) the bridge app, which
 * starts its foreground service — the PWA-side half of story 250 decision 6.
 */
export const HC_BRIDGE_LAUNCH_URL = 'intent://sync#Intent;scheme=hcbridge;package=dev.motivation.hcreader;end';

/**
 * Strava activities before this local date came in through the old Strava
 * cloud API (`source='strava'`) — skip them so history is not duplicated
 * (story 250 decision 3). Fit data is a brand-new stream: no cutoff.
 */
export const HC_STRAVA_CUTOVER_DATE = '2026-07-01';

/** One exercise session as served by the bridge's GET /activities. */
export interface BridgeActivity {
    id: string;
    source: string;
    exerciseType: number;
    start: string;
    end: string;
    durationSec: number;
    distanceMeters: number;
    /** Same-source active energy for the session window (story 259); null when the writer recorded none. */
    energyKcal: number | null;
}

export interface BridgeActivitiesResponse {
    generatedAt: string;
    rangeDays: number;
    activityCount: number;
    activities: BridgeActivity[];
}

/** One per-local-day step total as served by the bridge's GET /steps/daily (story 251). */
export interface BridgeDailySteps {
    date: string;
    steps: number;
}

export interface BridgeDailyStepsResponse {
    generatedAt: string;
    rangeDays: number;
    days: BridgeDailySteps[];
}

/** `daily_steps.source` value for bridge-ingested rows — HC aggregates across writers, so the writer package is not preserved. */
export const HC_STEPS_SOURCE = 'health_connect';

export type BridgeMapResult =
    | { kind: 'mapped'; activity: NewActivity; distanceMeters: number }
    | { kind: 'skipped'; reason: 'unknown_type' | 'unknown_source' | 'pre_cutover' };

export interface HcSyncSummary {
    created: number;
    skippedExisting: number;
    skippedPreCutover: number;
    skippedUnknownType: number;
    skippedUnknownSource: number;
    skippedFitOverlap: number;
    /** Days whose step total was new or changed (story 251); unchanged days are not re-written. */
    stepDaysUpserted: number;
    /** Existing HC rows without a burn value that this sync PATCHed with bridge energy (story 259). */
    energyBackfilled: number;
    /**
     * Newly-created activities that share an exact start with a pre-existing one
     * of the same source+type (a different HC record id — typically a partial
     * session HC later superseded, so it reads as a duplicate). Surfaced to the
     * user with a "delete the older one?" prompt rather than silently dropped.
     */
    collisions: HcSyncCollision[];
}

/** One same-start pair flagged by a sync (see {@link HcSyncSummary.collisions}). */
export interface HcSyncCollision {
    type: string;
    source: ActivitySource;
    /** Shared start instant (ISO); both rows begin here. */
    start: string;
    newId: string;
    newExternalId: string;
    newDurationMinutes: number;
    existingId: string;
    existingExternalId: string | null;
    existingDurationMinutes: number;
}

// HC ExerciseSessionRecord.exerciseType → activities.type. 81 is Strava's
// "other" — the owner's HIIT classes; HC carries nothing beyond duration for
// them (253-evidence), so they land as workout shells named via title edit.
const EXERCISE_TYPE_MAP: Record<number, ActivityType> = {
    56: 'running',
    57: 'running', // treadmill
    79: 'walking',
    8: 'cycling',
    81: 'workout', // Strava "other" (story 253)
};

const TITLE_BY_TYPE: Partial<Record<ActivityType, string>> = {
    running: 'Run',
    walking: 'Walk',
    cycling: 'Ride',
    workout: 'Workout',
};

const SOURCE_MAP: Record<string, ActivitySource> = {
    'com.strava': 'health_connect_strava',
    'com.google.android.apps.fitness': 'health_connect_android_fitness',
};

function mapExerciseType(exerciseType: number): ActivityType | null {
    return EXERCISE_TYPE_MAP[exerciseType] ?? null;
}

/** Projects the session's start instant into the app timezone's local date. */
function localDateOf(startIso: string, timeZone: string): string {
    return Temporal.Instant.from(startIso).toZonedDateTimeISO(timeZone).toPlainDate().toString();
}

/** The `start` instant an HC activity was ingested with, from its metadata blob (null if absent/unparseable). */
function activityStartInstant(metadata: string | null | undefined): string | null {
    if (!metadata) return null;
    try {
        const parsed = JSON.parse(metadata) as { start?: unknown };
        return typeof parsed.start === 'string' ? parsed.start : null;
    } catch {
        return null;
    }
}

/** Same source + type + exact start = the same real activity under two HC record ids. */
function collisionKey(source: string, type: string, start: string): string {
    return `${source}|${type}|${start}`;
}

export function mapBridgeActivity(bridge: BridgeActivity, timeZone: string): BridgeMapResult {
    const source = SOURCE_MAP[bridge.source];
    if (!source) return { kind: 'skipped', reason: 'unknown_source' };

    const type = mapExerciseType(bridge.exerciseType);
    if (!type) return { kind: 'skipped', reason: 'unknown_type' };

    const date = localDateOf(bridge.start, timeZone);
    if (source === 'health_connect_strava' && date < HC_STRAVA_CUTOVER_DATE) {
        return { kind: 'skipped', reason: 'pre_cutover' };
    }

    return {
        kind: 'mapped',
        distanceMeters: bridge.distanceMeters,
        activity: {
            type,
            source,
            title: TITLE_BY_TYPE[type] ?? type,
            date,
            duration_minutes: Math.round(bridge.durationSec / 60),
            // Real energy from the watch (story 259); undefined keeps the row
            // on the MET-estimate fallback (story 258).
            calories_burned: bridge.energyKcal ?? undefined,
            external_id: `hc_${bridge.id}`,
            metadata: JSON.stringify({
                start: bridge.start,
                end: bridge.end,
                hc_exercise_type: bridge.exerciseType,
            }),
        },
    };
}

function overlaps(a: BridgeActivity, b: BridgeActivity): boolean {
    const aStart = Temporal.Instant.from(a.start).epochMilliseconds;
    const aEnd = Temporal.Instant.from(a.end).epochMilliseconds;
    const bStart = Temporal.Instant.from(b.start).epochMilliseconds;
    const bEnd = Temporal.Instant.from(b.end).epochMilliseconds;
    return aStart < bEnd && bStart < aEnd;
}

/**
 * A run logged by both Strava and Fit collapses to the Strava activity (story
 * 250 decision 5): drop every Fit session whose time window overlaps a
 * same-type Strava session. Strava already carries distance + duration, so in
 * practice Fit adds nothing to enrich.
 */
export function dropFitOverlaps(activities: BridgeActivity[]): { kept: BridgeActivity[]; dropped: number } {
    const strava = activities.filter((a) => a.source === 'com.strava');
    const kept: BridgeActivity[] = [];
    let dropped = 0;
    for (const activity of activities) {
        if (activity.source !== 'com.google.android.apps.fitness') {
            kept.push(activity);
            continue;
        }
        const duplicate = strava.some(
            (s) => mapExerciseType(s.exerciseType) === mapExerciseType(activity.exerciseType) && overlaps(s, activity),
        );
        if (duplicate) {
            dropped++;
        } else {
            kept.push(activity);
        }
    }
    return { kept, dropped };
}

export class HealthConnectService {
    /** Cheap reachability probe for the Status screen dot. */
    static async pingBridge(): Promise<boolean> {
        try {
            const response = await fetch(`${HC_BRIDGE_URL}/ping`, { signal: AbortSignal.timeout(3_000) });
            return response.ok;
        } catch {
            return false;
        }
    }

    static async fetchBridgeActivities(): Promise<BridgeActivitiesResponse> {
        const response = await fetch(`${HC_BRIDGE_URL}/activities`);
        if (response.status === 429) throw new HcRateLimitError();
        if (!response.ok) {
            throw new Error(`Bridge /activities failed: ${response.status}`);
        }
        return response.json();
    }

    static async fetchBridgeDailySteps(): Promise<BridgeDailyStepsResponse> {
        const response = await fetch(`${HC_BRIDGE_URL}/steps/daily`);
        if (response.status === 429) throw new HcRateLimitError();
        if (!response.ok) {
            throw new Error(`Bridge /steps/daily failed: ${response.status}`);
        }
        return response.json();
    }

    /**
     * Full activity sync: bridge → map → dedup against the server window →
     * POST each new activity (+ PATCH distance). Errors are not swallowed —
     * a failing push aborts the sync and surfaces raw (fail loud).
     */
    static async sync(): Promise<HcSyncSummary> {
        try {
            const summary = await this.runSync();
            log.info('hc-sync: completed', summary);
            return summary;
        } catch (err) {
            log.error('hc-sync: failed', err);
            throw err;
        }
    }

    private static async runSync(): Promise<HcSyncSummary> {
        log.info('hc-sync: started');
        const bridge = await this.fetchBridgeActivities();
        const { kept, dropped } = dropFitOverlaps(bridge.activities);
        log.debug('hc-sync: bridge activities', {
            total: bridge.activities.length,
            rangeDays: bridge.rangeDays,
            fitOverlapsDropped: dropped,
        });

        const today = appTodayPlainDate();
        const from = today.subtract({ days: bridge.rangeDays + 1 }).toString();
        const existing = await HealthService.fetchActivitiesByDateRange(from, today.toString());
        const existingByExternalId = new Map(
            existing.filter((a) => a.external_id).map((a) => [a.external_id!, a]),
        );

        const timeZone = getAppTimeZone();
        const summary: HcSyncSummary = {
            created: 0,
            skippedExisting: 0,
            skippedPreCutover: 0,
            skippedUnknownType: 0,
            skippedUnknownSource: 0,
            skippedFitOverlap: dropped,
            stepDaysUpserted: 0,
            energyBackfilled: 0,
            collisions: [],
        };

        // Index every activity we know about by (source, type, exact start) so a
        // freshly-created row can be matched against an earlier one sharing the
        // same start — the partial-vs-superseded duplicate (see HcSyncCollision).
        // Seeded with the pre-sync rows and extended as we create, so both the
        // "partial synced last time" and "both created this run" cases are caught.
        interface CollisionCandidate { id: string; externalId: string | null; durationMinutes: number }
        const byStart = new Map<string, CollisionCandidate[]>();
        const indexByStart = (source: string, type: string, start: string | null, c: CollisionCandidate): void => {
            if (!start) return;
            const key = collisionKey(source, type, start);
            const bucket = byStart.get(key);
            if (bucket) bucket.push(c);
            else byStart.set(key, [c]);
        };
        for (const a of existing) {
            indexByStart(a.source, a.type, activityStartInstant(a.metadata), {
                id: a.id,
                externalId: a.external_id ?? null,
                durationMinutes: a.duration_minutes ?? 0,
            });
        }

        for (const bridgeActivity of kept) {
            const result = mapBridgeActivity(bridgeActivity, timeZone);
            if (result.kind === 'skipped') {
                if (result.reason === 'pre_cutover') summary.skippedPreCutover++;
                else if (result.reason === 'unknown_type') summary.skippedUnknownType++;
                else summary.skippedUnknownSource++;
                continue;
            }

            const existingRow = existingByExternalId.get(result.activity.external_id!);
            if (existingRow) {
                summary.skippedExisting++;
                // Story 259 backfill: rows ingested before the bridge served
                // energy get the real value once a re-sync reports it.
                if (result.activity.calories_burned != null && existingRow.calories_burned == null) {
                    await HealthService.updateActivity(existingRow.id, { calories_burned: result.activity.calories_burned });
                    log.debug('hc-sync: backfilled energy', {
                        external_id: result.activity.external_id,
                        calories_burned: result.activity.calories_burned,
                    });
                    summary.energyBackfilled++;
                }
                continue;
            }

            const created = await HealthService.createActivity(result.activity);
            if (result.distanceMeters > 0) {
                await HealthService.upsertCardioDetails(created.id, { distance_m: result.distanceMeters });
            }

            // Flag (don't drop) any earlier row sharing this exact start — HC gave
            // the finished session a new record id, so external_id dedup can't see
            // it. The user resolves it from the Status screen prompt.
            const newExternalId = result.activity.external_id!;
            const newDuration = result.activity.duration_minutes ?? 0;
            const start = bridgeActivity.start;
            for (const other of byStart.get(collisionKey(result.activity.source, result.activity.type, start)) ?? []) {
                summary.collisions.push({
                    type: result.activity.type,
                    source: result.activity.source,
                    start,
                    newId: created.id,
                    newExternalId,
                    newDurationMinutes: newDuration,
                    existingId: other.id,
                    existingExternalId: other.externalId,
                    existingDurationMinutes: other.durationMinutes,
                });
            }
            indexByStart(result.activity.source, result.activity.type, start, {
                id: created.id,
                externalId: newExternalId,
                durationMinutes: newDuration,
            });

            log.debug('hc-sync: created activity', {
                external_id: result.activity.external_id,
                type: result.activity.type,
                source: result.activity.source,
                date: result.activity.date,
                distance_m: result.distanceMeters,
            });
            summary.created++;
        }

        summary.stepDaysUpserted = await this.syncDailySteps(from, today.toString());

        return summary;
    }

    /**
     * Steps leg of the sync (story 251): bridge per-day totals are upserted by
     * date, but only days whose total is new or changed are written — an
     * unchanged re-sync must not churn the server (or the offline pending
     * queue) with ~30 no-op writes.
     */
    private static async syncDailySteps(from: string, to: string): Promise<number> {
        const bridge = await this.fetchBridgeDailySteps();
        const existing = await HealthService.fetchDailySteps(from, to);
        const existingByDate = new Map(existing.map((row) => [row.date, row.steps]));

        let upserted = 0;
        for (const day of bridge.days) {
            if (existingByDate.get(day.date) === day.steps) continue;
            await HealthService.upsertDailySteps(day.date, { steps: day.steps, source: HC_STEPS_SOURCE });
            upserted++;
        }
        log.debug('hc-sync: daily steps', { bridgeDays: bridge.days.length, upserted });
        return upserted;
    }
}
