import '../../../status-pill/status-dot/status-dot.component.js';
import type { StatusDot } from '../../../status-pill/status-dot/status-dot.component.js';
import { HC_BRIDGE_LAUNCH_URL, type HcSyncCollision } from '../../../../services/health-connect.service.js';
import { createHcSyncEvent, createHcCollisionDeleteEvent } from '../../status-events.js';

/** Reachability of the on-phone Health Connect bridge; `null` = not yet probed. */
export interface HcBridgeStatus {
    reachable: boolean | null;
}

const template = document.createElement('template');
template.innerHTML = `
    <style>
        .hc-cooldown { display: block; margin-top: 6px; font-size: 0.85em; opacity: 0.8; }
        .hc-collisions { display: flex; flex-direction: column; gap: 8px; margin-top: 10px; }
        .hc-collision { border: 1px solid currentColor; border-radius: 8px; padding: 8px 10px; font-size: 0.88em; }
        .hc-collision p { margin: 0 0 6px; }
        .hc-collision .row { display: flex; flex-wrap: wrap; gap: 6px; }
        .hc-collision button { font: inherit; padding: 4px 8px; border-radius: 6px; cursor: pointer; }
    </style>
    <div class="section">
        <div class="section-header">
            <status-dot id="dot" title="Health Connect bridge"></status-dot>
            <h3 class="section-title">Connected Services</h3>
        </div>

        <div class="status-grid">
            <span class="status-label">HC bridge: <span id="hc-badge" class="status-badge"></span></span>
            <span class="status-label" id="hc-last" hidden></span>
        </div>

        <div class="actions-row">
            <button type="button" class="action-btn action-btn--primary" id="hc-sync">Sync Health Connect</button>
            <a id="hc-open" class="action-btn" href="${HC_BRIDGE_LAUNCH_URL}" hidden>Open bridge app</a>
        </div>
        <span class="hc-cooldown" id="hc-cooldown" hidden></span>

        <div class="hc-collisions" id="hc-collisions" hidden></div>
    </div>
`;

/**
 * Health Connect bridge block (story 250 — replaced the Strava OAuth block).
 * The bridge runs on the phone at 127.0.0.1; on any other device it simply
 * reads "Unreachable". Sync is dispatched to the status screen, which owns
 * the service call and feedback.
 *
 * The sync button stays disabled while a sync is in flight and through a
 * cooldown after Health Connect rate-limits reads — otherwise rapid re-taps
 * pile more reads onto an already-throttled quota and make it worse.
 */
export class ServicesSection extends HTMLElement {
    private _hcStatus: HcBridgeStatus = { reachable: null };
    private _syncing = false;
    private _cooldownUntil = 0;
    private cooldownTimer: ReturnType<typeof setInterval> | null = null;

    private dot!: StatusDot;
    private hcBadge!: HTMLSpanElement;
    private hcLast!: HTMLSpanElement;
    private syncBtn!: HTMLButtonElement;
    private openLink!: HTMLAnchorElement;
    private cooldownEl!: HTMLSpanElement;
    private collisionsEl!: HTMLDivElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.appendChild(template.content.cloneNode(true));

        this.dot = shadow.getElementById('dot') as StatusDot;
        this.hcBadge = shadow.getElementById('hc-badge') as HTMLSpanElement;
        this.hcLast = shadow.getElementById('hc-last') as HTMLSpanElement;
        this.syncBtn = shadow.getElementById('hc-sync') as HTMLButtonElement;
        this.openLink = shadow.getElementById('hc-open') as HTMLAnchorElement;
        this.cooldownEl = shadow.getElementById('hc-cooldown') as HTMLSpanElement;
        this.collisionsEl = shadow.getElementById('hc-collisions') as HTMLDivElement;

        this.syncBtn.addEventListener('click', () => {
            if (this.syncBtn.disabled) return;
            this.setSyncing(true);
            this.dispatchEvent(createHcSyncEvent());
        });

        this.render();
    }

    disconnectedCallback() {
        if (this.cooldownTimer) clearInterval(this.cooldownTimer);
    }

    set hcStatus(val: HcBridgeStatus) {
        this._hcStatus = val;
        this.render();
    }

    /** Toggle the in-flight state; the status screen sets false when the sync settles. */
    setSyncing(syncing: boolean): void {
        this._syncing = syncing;
        this.render();
    }

    /**
     * Block sync for `seconds` after Health Connect rate-limited us, with a live
     * countdown so the button re-enabling isn't a surprise.
     */
    startCooldown(seconds: number): void {
        this._cooldownUntil = Date.now() + seconds * 1000;
        if (this.cooldownTimer) clearInterval(this.cooldownTimer);
        this.cooldownTimer = setInterval(() => {
            if (Date.now() >= this._cooldownUntil) {
                clearInterval(this.cooldownTimer!);
                this.cooldownTimer = null;
                this._cooldownUntil = 0;
            }
            this.render();
        }, 1000);
        this.render();
    }

    /**
     * Result of the most recent sync this session — stays visible (unlike the
     * 5-second feedback toast) so "did it work?" has an answer on the screen.
     */
    set lastSyncResult(text: string) {
        this.hcLast.textContent = text;
        this.hcLast.hidden = text === '';
    }

    /**
     * Same-start duplicates a sync flagged (story: traveling-user HC partials).
     * Each renders a "delete which copy?" prompt; the chosen id is dispatched to
     * the status screen, which owns the delete call.
     */
    showCollisions(collisions: HcSyncCollision[]): void {
        this.collisionsEl.replaceChildren();
        this.collisionsEl.hidden = collisions.length === 0;
        for (const c of collisions) {
            this.collisionsEl.appendChild(this.buildCollisionCard(c));
        }
    }

    private buildCollisionCard(c: HcSyncCollision): HTMLDivElement {
        const card = document.createElement('div');
        card.className = 'hc-collision';
        const label = c.type.charAt(0).toUpperCase() + c.type.slice(1);
        const at = new Date(c.start).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

        const p = document.createElement('p');
        p.textContent = `Possible duplicate: a new ${label} (${c.newDurationMinutes} min) and an existing one `
            + `(${c.existingDurationMinutes} min) both start at ${at}. Health Connect likely re-recorded it — delete one?`;

        const row = document.createElement('div');
        row.className = 'row';
        row.appendChild(this.deleteButton(`Delete previous (${c.existingDurationMinutes}m)`, c.existingId, card));
        row.appendChild(this.deleteButton(`Delete new (${c.newDurationMinutes}m)`, c.newId, card));
        const keep = document.createElement('button');
        keep.type = 'button';
        keep.textContent = 'Keep both';
        keep.addEventListener('click', () => this.dismissCard(card));
        row.appendChild(keep);

        card.append(p, row);
        return card;
    }

    private deleteButton(text: string, activityId: string, card: HTMLDivElement): HTMLButtonElement {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.textContent = text;
        btn.addEventListener('click', () => {
            this.dispatchEvent(createHcCollisionDeleteEvent(activityId));
            this.dismissCard(card);
        });
        return btn;
    }

    private dismissCard(card: HTMLDivElement): void {
        card.remove();
        this.collisionsEl.hidden = this.collisionsEl.childElementCount === 0;
    }

    /** Pill-dot color: reachable is green; unreachable is plain gray — a phone-only service being absent (e.g. on desktop) is normal, not an error. */
    static getStatus(reachable: boolean | null) {
        return { color: reachable ? 'green' : 'gray' };
    }

    private render() {
        const { reachable } = this._hcStatus;

        this.dot.setAttribute('color', reachable === null ? 'gray' : reachable ? 'green' : 'red');
        this.hcBadge.textContent = reachable === null ? 'Checking…' : reachable ? 'Reachable' : 'Unreachable';
        this.hcBadge.className = `status-badge ${reachable ? 'status-badge--active' : 'status-badge--inactive'}`;

        this.openLink.hidden = reachable !== false;

        const cooldownMs = this._cooldownUntil - Date.now();
        const cooling = cooldownMs > 0;
        // Disabled while a sync is in flight or cooling down — NOT re-enabled by a
        // status re-render mid-sync (the old bug that allowed rapid re-taps).
        this.syncBtn.disabled = this._syncing || cooling;
        this.syncBtn.textContent = this._syncing ? 'Syncing…' : 'Sync Health Connect';

        this.cooldownEl.hidden = !cooling;
        if (cooling) {
            this.cooldownEl.textContent = `Health Connect rate-limited — retry in ${Math.ceil(cooldownMs / 1000)}s`;
        }
    }
}

if (!customElements.get('services-status-section')) {
    customElements.define('services-status-section', ServicesSection);
}
